namespace sv_f114527d7c3b49ca83fb613955019ee9.Client.Auth;

// Serializable DTO used to persist auth state from server to WebAssembly.
public sealed class UserInfo
{
    public required string Email { get; set; }
    public required string[] Roles { get; set; }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_f114527d7c3b49ca83fb613955019ee9.Client.Auth;

// Client-side provider that reads auth state persisted by the server
// via PersistentComponentState, so identity survives the WASM handoff.
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authenticationStateTask;

    public PersistentAuthenticationStateProvider(PersistentComponentState state)
    {
        if (!state.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo) || userInfo is null)
        {
            _authenticationStateTask = _unauthenticated;
            return;
        }

        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, userInfo.Email),
            new(ClaimTypes.Email, userInfo.Email),
        };

        foreach (var role in userInfo.Roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        _authenticationStateTask = Task.FromResult(
            new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity(claims, "PersistentAuth"))));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authenticationStateTask;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Server;

namespace sv_f114527d7c3b49ca83fb613955019ee9.Auth;

// Simulates a logged-in user with hardcoded claims.
public sealed class FakeAuthenticationStateProvider : ServerAuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _state;

    static FakeAuthenticationStateProvider()
    {
        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, "bob@example.com"),
            new(ClaimTypes.Email, "bob@example.com"),
            new(ClaimTypes.Role, "User"),
            new(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, "FakeAuth");
        _state = Task.FromResult(new AuthenticationState(new ClaimsPrincipal(identity)));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _state;
}

using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_f114527d7c3b49ca83fb613955019ee9.Client.Auth;

namespace sv_f114527d7c3b49ca83fb613955019ee9.Auth;

// Subscribes to the server-side AuthenticationStateProvider and serializes
// the current user's claims into PersistentComponentState so the WASM
// client can pick them up after the interactive runtime activates.
public sealed class PersistingServerAuthenticationStateProvider : IHostEnvironmentAuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _state;
    private readonly PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authStateTask;

    public PersistingServerAuthenticationStateProvider(
        AuthenticationStateProvider authStateProvider,
        PersistentComponentState state)
    {
        _state = state;

        // Listen for auth state changes.
        authStateProvider.AuthenticationStateChanged += OnAuthenticationStateChanged;

        // Register to persist when the component tree is being serialized for WASM.
        _subscription = state.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public void SetAuthenticationState(Task<AuthenticationState> authenticationStateTask)
    {
        _authStateTask = authenticationStateTask;
    }

    private void OnAuthenticationStateChanged(Task<AuthenticationState> task)
    {
        _authStateTask = task;
    }

    private async Task OnPersistingAsync()
    {
        if (_authStateTask is null) return;

        var authState = await _authStateTask;
        var principal = authState.User;

        if (principal.Identity?.IsAuthenticated != true) return;

        var email = principal.FindFirst(System.Security.Claims.ClaimTypes.Email)?.Value ?? "";
        var roles = principal.FindAll(System.Security.Claims.ClaimTypes.Role)
                             .Select(c => c.Value)
                             .ToArray();

        _state.PersistAsJson(nameof(UserInfo), new UserInfo
        {
            Email = email,
            Roles = roles,
        });
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

